  <text x="35" y="184" fill="#71717a" font-size="12">Margen para distorsionar el VWAP — casi ninguno</text>
  <rect x="380" y="80" width="300" height="130" rx="8" fill="#18181b" stroke="#3f3f46"/>
  <text x="395" y="105" fill="#f87171" font-size="14" font-weight="700">Mercado de Baja Liquidez</text>
  <rect x="395" y="120" width="270" height="24" fill="#27272a"/>
  <rect x="395" y="120" width="108" height="24" fill="#f59e0b"/>
